const fs=require("fs"),{execSync:execSync}=require("child_process"),cleanHtml=execSync("git show bf9cd5e:index.html").toString("utf8"),cleanIcons=[...cleanHtml.matchAll(/class="need-icon">([^<]+)</g)].map(e=>e[1]);let html=fs.readFileSync("index.html","utf8"),count=0;html=html.replace(/(?<=class="need-icon">)[^<]+(?=<)/g,()=>{const e=cleanIcons[count]||"";return count++,e}),fs.writeFileSync("index.html",html,"utf8"),console.log(`✅ Replaced ${count} need-icon emojis`);const verify=[...fs.readFileSync("index.html","utf8").matchAll(/class="need-icon">([^<]+)</g)].map(e=>e[1]);verify.forEach((e,c)=>console.log(`  ${c+1}. ${e}`));